void *qemu_thread_join(QemuThread *thread)

{

    QemuThreadData *data;

    void *ret;

    HANDLE handle;



    data = thread->data;

    if (!data) {

        return NULL;

    }

    /*

     * Because multiple copies of the QemuThread can exist via

     * qemu_thread_get_self, we need to store a value that cannot

     * leak there.  The simplest, non racy way is to store the TID,

     * discard the handle that _beginthreadex gives back, and

     * get another copy of the handle here.

     */

    EnterCriticalSection(&data->cs);

    if (!data->exited) {

        handle = OpenThread(SYNCHRONIZE, FALSE, thread->tid);

        LeaveCriticalSection(&data->cs);

        WaitForSingleObject(handle, INFINITE);

        CloseHandle(handle);

    } else {

        LeaveCriticalSection(&data->cs);

    }

    ret = data->ret;

    DeleteCriticalSection(&data->cs);

    g_free(data);

    return ret;

}

static int s337m_probe(AVProbeData *p)

{

    uint64_t state = 0;

    int markers[3] = { 0 };

    int i, sum, max, data_type, data_size, offset;

    uint8_t *buf;



    for (buf = p->buf; buf < p->buf + p->buf_size; buf++) {

        state = (state << 8) | *buf;

        if (!IS_LE_MARKER(state))

            continue;



        if (IS_16LE_MARKER(state)) {

            data_type = AV_RL16(buf + 1);

            data_size = AV_RL16(buf + 3);

            buf += 4;

        } else {

            data_type = AV_RL24(buf + 1);

            data_size = AV_RL24(buf + 4);

            buf += 6;

        }



        if (s337m_get_offset_and_codec(NULL, state, data_type, data_size, &offset, NULL))

            continue;



        i = IS_16LE_MARKER(state) ? 0 : IS_20LE_MARKER(state) ? 1 : 2;

        markers[i]++;



        buf  += offset;

        state = 0;

    }



    sum = max = 0;

    for (i = 0; i < FF_ARRAY_ELEMS(markers); i++) {

        sum += markers[i];

        if (markers[max] < markers[i])

            max = i;

    }



    if (markers[max] > 3 && markers[max] * 4 > sum * 3)

        return AVPROBE_SCORE_EXTENSION + 1;



    return 0;

}

static int aea_read_header(AVFormatContext *s)

{

    AVStream *st = avformat_new_stream(s, NULL);

    if (!st)

        return AVERROR(ENOMEM);



    /* Parse the amount of channels and skip to pos 2048(0x800) */

    avio_skip(s->pb, 264);

    st->codec->channels = avio_r8(s->pb);

    avio_skip(s->pb, 1783);





    st->codec->codec_type     = AVMEDIA_TYPE_AUDIO;

    st->codec->codec_id       = AV_CODEC_ID_ATRAC1;

    st->codec->sample_rate    = 44100;

    st->codec->bit_rate       = 292000;



    if (st->codec->channels != 1 && st->codec->channels != 2) {

        av_log(s,AV_LOG_ERROR,"Channels %d not supported!\n",st->codec->channels);

        return -1;

    }



    st->codec->channel_layout = (st->codec->channels == 1) ? AV_CH_LAYOUT_MONO : AV_CH_LAYOUT_STEREO;



    st->codec->block_align = AT1_SU_SIZE * st->codec->channels;

    return 0;

}

static int _get_transform_coeffs(uint8_t *exps, uint8_t *bap, float chcoeff,

        float *samples, int start, int end, int dith_flag, GetBitContext *gb,

        dither_state *state)

{

    int16_t mantissa;

    int i;

    int gcode;

    mant_group l3_grp, l5_grp, l11_grp;



    for (i = 0; i < 3; i++)

        l3_grp.gcodes[i] = l5_grp.gcodes[i] = l11_grp.gcodes[i] = -1;

    l3_grp.gcptr = l5_grp.gcptr = 3;

    l11_grp.gcptr = 2;



    i = 0;

    while (i < start)

        samples[i++] = 0;



    for (i = start; i < end; i++) {

        switch (bap[i]) {

            case 0:

                if (!dith_flag)

                    mantissa = 0;

                else

                    mantissa = dither_int16(state);

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;



            case 1:

                if (l3_grp.gcptr > 2) {

                    gcode = get_bits(gb, qntztab[1]);

                    if (gcode > 26)

                        return -1;

                    l3_grp.gcodes[0] = gcode / 9;

                    l3_grp.gcodes[1] = (gcode % 9) / 3;

                    l3_grp.gcodes[2] = (gcode % 9) % 3;

                    l3_grp.gcptr = 0;

                }

                mantissa = l3_q_tab[l3_grp.gcodes[l3_grp.gcptr++]];

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;



            case 2:

                if (l5_grp.gcptr > 2) {

                    gcode = get_bits(gb, qntztab[2]);

                    if (gcode > 124)

                        return -1;

                    l5_grp.gcodes[0] = gcode / 25;

                    l5_grp.gcodes[1] = (gcode % 25) / 5;

                    l5_grp.gcodes[2] = (gcode % 25) % 5;

                    l5_grp.gcptr = 0;

                }

                mantissa = l5_q_tab[l5_grp.gcodes[l5_grp.gcptr++]];

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;



            case 3:

                mantissa = get_bits(gb, qntztab[3]);

                if (mantissa > 6)

                    return -1;

                mantissa = l7_q_tab[mantissa];

                samples[i] = to_float(exps[i], mantissa);

                break;



            case 4:

                if (l11_grp.gcptr > 1) {

                    gcode = get_bits(gb, qntztab[4]);

                    if (gcode > 120)

                        return -1;

                    l11_grp.gcodes[0] = gcode / 11;

                    l11_grp.gcodes[1] = gcode % 11;

                }

                mantissa = l11_q_tab[l11_grp.gcodes[l11_grp.gcptr++]];

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;



            case 5:

                mantissa = get_bits(gb, qntztab[5]);

                if (mantissa > 14)

                    return -1;

                mantissa = l15_q_tab[mantissa];

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;



            default:

                mantissa = get_bits(gb, qntztab[bap[i]]) << (16 - qntztab[bap[i]]);

                samples[i] = to_float(exps[i], mantissa) * chcoeff;

                break;

        }

    }



    i = end;

    while (i < 256)

        samples[i++] = 0;



    return 0;

}

